struct node {
	ll id;
	db d;
	bool operator<(const node& a)const {
		return a.d < d;
	}
};
void solve(int CASE)
{
	ll sx, sy, tx, ty; cin >> sx >> sy >> tx >> ty;
	ll vf, vp, vh; cin >> vf >> vp >> vh;

	ll n; cin >> n;
	var p = vector<tuple<ll, ll, ll>>();
	fa(i, 0, n) {
		ll x, y, v; cin >> x >> y >> v;
		if (v > vp)p.pb({ x,y,v });
	}

	ll m = p.size() - 1;
	var D = Vec2<db>(m + 1, m + 1);
	fa(i, 0, m)fa(j, 0, m) {
		const var& [x, y, v] = p[i];
		const var& [nx, ny, nv] = p[j];
		D[i][j] = hypot(x - nx, y - ny);
	}

	// 朴素 dij
	var dis = vector<db>(m + 1, 1e18);
	var vis = vector<bool>(m + 1);
	dis[0] = 0;
	fa(_, 0, m) {
		int now = -1;
		fa(i, 0, m)
			if (!vis[i] and (now == -1 or dis[i] < dis[now]))
				now = i;
		vis[now] = 1;
		const var& [x, y, v] = p[now];
		fa(to, 0, m) {
			if (to == now)continue;
			db w = (D[now][to] * v) / (vh * (v - vp));
			if (dis[to] > dis[now] + w)dis[to] = dis[now] + w;
		}
	}

	db ans = 1e18;
	fa(i, 0, m) {
		const var& [x, y, v] = p[i];
		db w = (hypot(x - tx, y - ty) * v) / (vh * (v - vp));
		ans = min(ans, dis[i] + w);
	}

	cout << fixed << setprecision(12) << ans << endl;
	return;
}
